          kind: "approve-for-session" as const,
          approval: { kind: "memory" as const },
        };
      case "custom-tool":
        return {
          kind: "approve-for-session" as const,
          approval: {
            kind: "custom-tool" as const,
            toolName: request.toolName,
          },
        };
      default:
        return undefined;
    }
  };

  switch (decision) {
    case "accept":
      return { kind: "approve-once" };
